var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"느려, 느리다고──!","JPN":"遅い、遅いぞ──！","ENG":"Too slow. You're way too slow──!","TWN":"太慢、太慢了──！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"고작 이 정도로 나를 따라잡을 수 있을 것 같아?","JPN":"この程度で私に追いつけると思ってんの？","ENG":"You really think you can catch me with just that?","TWN":"就這點程度也想追上我？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"크윽, 복병이 있었을 줄이야!","JPN":"くうっ、伏兵がいたとは！","ENG":"Tch, an ambush!","TWN":"嘖，居然還有埋伏！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"검은 신부는 대체 뭘 뜸을 들이는 거지? 그분께서 점지한 시간이 머지않았는데……!","JPN":"黒い神父は何をもたもたしている？　あの方が示した時刻が迫っているというのに……！","ENG":"What is that Black Priest even stalling for? The time bestowed by Him is almost at hand...!","TWN":"黑色神父到底在磨蹭什麼？他指定的時間就快到了……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"신도들이여! 반드시 그릇을 확보해야……!","JPN":"信徒たちよ！　必ず器を確保せねば……！","ENG":"Believers. We must secure the vessel no matter what...!","TWN":"信徒們！一定要確保器皿……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CULTIST_CAMPAMENTO_NULL_NULL","text":{"KOREA":"크헉……!!","JPN":"かはっ……！！","ENG":"Gah...!!","TWN":"咳啊……！！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_CAMPAMENTO_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_BIG_02"},{"id":"L15_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"탈출 루트 확보 완료.","JPN":"脱出ルート確保完了。","ENG":"Escape route secured.","TWN":"逃生路線確認完畢。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL"},{"id":"L16_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"서둘러, 도로시. 지금 이쪽을 향해 다수의 생체 신호가 몰려오고 있어.","JPN":"急いで、ドロシー。多数の生体信号がこっちに向かってきてる。","ENG":"Hurry, Dorothy. Multiple biometric signals are converging on this location.","TWN":"快，桃樂絲。大量生物訊號正朝這裡聚集。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"<color=#ffd34c>그걸</color> 쓰자, 도로시.","JPN":"<color=#ffd34c>あれ</color>を使うよ、ドロシー。","ENG":"Let's use <color=#ffd34c>that</color>, Dorothy.","TWN":"<color=#ffd34c>用那個吧</color>，桃樂絲。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"계산 결과, 그 속도라면 여기서 단숨에 벗어날 수 있을 거야.","JPN":"計算結果、あの速度なら一気にここから逃げられるはず。","ENG":"According to my calculations, with that speed we can break out of here in one go.","TWN":"計算結果顯示，那個速度的話能一口氣離開這裡。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"자, 잠깐? 그거라니? 그게 뭔데……?","JPN":"ま、待って。あれって何……？","ENG":"W-wait. \\"That\\"? What's that supposed to be...?","TWN":"等、等等？那個是指什麼……？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"헴스워스 아저씨가 개량한 도로시 구두의 새로운 기능이야.","JPN":"ヘムズワースおじさんが改良してくれた、ドロシーの靴の新しい機能だよ。","ENG":"It is a new function added to Dorothy's shoes by Helmsworth.","TWN":"那是桃樂絲鞋子的新功能，漢姆沃斯大叔改良的。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"순간적으로 구두의 출력을 끌어 올려서, 로켓처럼 하늘을 날 수 있게 돼.","JPN":"瞬時に靴の出力を引き上げて、ロケットみたいに空を飛べるようになる。","ENG":"By momentarily boosting the shoes' output, it lets you launch into the air like a rocket.","TWN":"瞬間提高輸出，像火箭一樣飛上天空。"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"하늘을 난다고?","JPN":"空を飛ぶ？","ENG":"Fly into the air?","TWN":"飛、飛上天空？"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"물론, 그 뒤로는 얼마간 빠르게 움직일 수 없게 되지만…….","JPN":"もちろん、その後しばらくは速く動けなくなるけど……","ENG":"Of course, you will not be able to move quickly for a while afterward...","TWN":"雖然之後一段時間內會無法高速行動……"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"좋아, 둘 다 꽉 잡아!","JPN":"よし、2人ともしっかり捕まって！","ENG":"All right. Hold on tight, both of you.","TWN":"好，兩個人都抓緊了！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"자, 잠깐! 도로시…! 나는 아직 마음에 준비가……!","JPN":"ま、待って！　ドロシーちゃん……！　私っ、まだ心の準備が……！","ENG":"W-wait. Dorothy...! I'm not mentally ready yet...!","TWN":"等、等一下！桃樂絲……！我還沒做好心理準備……！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"레드 슈즈, 롱 스트라이드! 고!","JPN":"レッドシューズ、ロングストライド！　ゴー！","ENG":"Red Shoes, Long Strides! Go!","TWN":"紅鞋，長距離衝刺！啟動！"},"stage":{"bg":"NEWTOWN_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"으아, 으아아아아아아아아────!!","JPN":"う、うあああああああ────！！","ENG":"Aah– AAAAAAAAAHHH────!!","TWN":"啊啊啊啊啊啊啊啊──！！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도시가, 사람들이────!!","JPN":"都市が、みんなが────！！","ENG":"The city, the people────!!","TWN":"城市、大家────！！"},"stage":{"bg":"MAINSTREAM_000008","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"흠, 으음…….","JPN":"う、ううん……","ENG":"Hnng, mm...","TWN":"嗯，唔嗯……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L1_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리온, 괜찮아? 정신이 좀 들어?","JPN":"リオン、大丈夫？　気がついた？","ENG":"Liona, are you okay? Can you tell where you are?","TWN":"萊恩，還好嗎？清醒了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"바이탈 체크 완료. 뇌파 정상 확인. 괜찮아, 정상이야.","JPN":"バイタルチェック完了。脳波正常確認。大丈夫、無事だよ。","ENG":"Vital check complete. Brain waves normal. She is fine.","TWN":"生命跡象確認完畢。腦波正常，沒問題。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L3_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"설마 이런 걸로 기절해 버릴 줄이야. 리온은 여전히 겁쟁이네.","JPN":"まさかこんなことで気絶するとは、リオンは相変わらず臆病者だね。","ENG":"I did not expect you to pass out from something like that. You are still a scaredy-cat, Liona.","TWN":"居然這樣就昏倒了，萊恩還是一樣膽小。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"얘들아…….","JPN":"二人とも……","ENG":"You guys...","TWN":"你們……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"도와줘서 고마워.","JPN":"助けてくれてありがとう。","ENG":"Thank you for helping me.","TWN":"謝謝你們救了我。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그리고 나, 너희가 보고 싶었어.","JPN":"私、二人に会いたかった。","ENG":"And I... I really missed you.","TWN":"還有，我真的很想你們。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"……나도 보고싶었어, 리온.","JPN":"……私も会いたかったよ、リオン。","ENG":"...I missed you too, Liona.","TWN":"……我也是，萊恩。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"맥박 지수 상승. 꺄꺄. 분위기 뜨겁네. 두 사람.","JPN":"脈拍数上昇。キャ～熱い熱い。","ENG":"Pulse rising. Wow. Things are heating up between you two.","TWN":"脈搏指數上升。嘻嘻，氣氛好熱烈呢，你們兩個。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L13_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"시, 시끄럽거든!?","JPN":"う、うるさい！","ENG":"H-hey, knock it off!","TWN":"吵、吵死了啦！？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"근데 그건 그거고. 난 아직 납득이 하나도 안 되거든?","JPN":"それはそうとして。ワタシはまだ納得できてない。","ENG":"But putting that aside, I still do not understand this at all.","TWN":"不過先不說這個，我還是一點都想不通耶？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"리온, 네가 왜 샤레이드에 있지? 카운터 아카데미에 편입한 거 아니었어?","JPN":"リオン、なぜアナタがシャレードにいるの？　カウンターアカデミーに編入したんじゃなかった？","ENG":"Liona, why are you in Charade? Didn't you transfer to the Counter Academy?","TWN":"萊恩，為什麼你會在查雷德？你不是編入制裁者學院了嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그게 말이지…….","JPN":"それがね……","ENG":"Well, about that...","TWN":"那個……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"사실은 초대장을 받았거든…….","JPN":"実は、招待状が送られてきて……","ENG":"I actually received an invitation...","TWN":"其實我收到了一封邀請函……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"초대장이라고?","JPN":"招待状？","ENG":"An invitation?","TWN":"邀請函？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"응. 토토 문제로 날 도와주었던 사람이 있어.","JPN":"うん。トトの件で私を助けてくれた人がいるの。","ENG":"Yeah. There was someone who helped me with Toto.","TWN":"嗯，之前有個人幫我處理托托的問題。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"<color=#ffd34c>프리드웬 기관</color>이라는 곳에서 보낸 초대장인데…….","JPN":"<color=#ffd34c>プリドウェン機関</color>ってところから来た招待状なんだけど……","ENG":"It was an invitation from a place called the <color=#ffd34c>Prydwen Institution</color>...","TWN":"邀請函來自<color=#ffd34c>普利多溫機關</color>……"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"아마도 그곳에서 그 사람을 다시 만날 수 있을 것 같았거든.","JPN":"そこに行けば、その人に会えるんじゃないかって気がして。","ENG":"I thought I might be able to meet that person there again.","TWN":"我想或許能在那裡再見到那個人。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그래서 초대장에 적혀 있던 대로 샤레이드에 온 거야.","JPN":"それで招待状に書かれていた通り、シャレードに来たの。","ENG":"So I came to Charade, just like the invitation said.","TWN":"所以就按照邀請函上寫的來查雷德了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"다시 만나면, 고맙다는 인사를 하고 싶었거든.","JPN":"また会えたら、お礼を言いたかった。","ENG":"I wanted to thank them properly if I met them again.","TWN":"我想再見他一次，跟他說聲謝謝。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"잠깐, 아마도라고……?","JPN":"待って、「気がして」……？","ENG":"\\"If you met them\\"...?","TWN":"等等，什麼叫或許……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼, 지금 그 편지 달랑 하나 믿고 그라운드 원에서 샤레이드까지 온 거야?","JPN":"じゃあ、その手紙一通だけを頼りに、グラウンド・ワンからシャレードまで来たってこと？","ENG":"So you came all the way from Ground One to Charade with nothing but that letter?","TWN":"你該不會只憑那一封信，就從G1跑來查雷德吧？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"여기 물가가 만만치 않을 텐데? 돈은? 숙박은 어떻게 한 건데?","JPN":"ここの物価高いだろ。お金は？　宿はどうしてたんだよ？","ENG":"You know the cost of living here is no joke, right? What about money? Where did you stay?","TWN":"這裡的物價可不便宜耶？錢呢？你又要住哪？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"토토를 얻은 뒤로, 노숙이라면 이미 익숙한 걸?","JPN":"トトに出会ってから、野宿には慣れてるから。","ENG":"After I got Toto, sleeping rough is nothing new to me.","TWN":"拿到托托之後，露宿街頭我早就習慣了。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"밥은 무료 급식소에… 여벌 옷이라면 아카데미 편입할 때 받은 게 있고 또…….","JPN":"食事は炊き出しの方々にお世話になって……着替えはアカデミーに編入した時もらったものがあるし……それに……","ENG":"For food, there are free meal centers... and I still have spare clothes from when I transferred to the Academy, and–","TWN":"吃飯在收容所……也有在編入學院時拿到的換洗衣物……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그, 그만……!","JPN":"ス、ストップ……！","ENG":"H-hold it...!","TWN":"夠、夠了……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"알겠어, 말 안 해도 알겠으니까……!","JPN":"わかった、わかったから……！","ENG":"I get it. You don't have to say any more...!","TWN":"我懂了，不用再說了……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"대책없구만. 리온답다면 리온답네.","JPN":"行き当たりばったりだね。リオンらしいといったらリオンらしいけど。","ENG":"So reckless. Still, that is very like you, Liona.","TWN":"真是沒救了，還真像萊恩的風格呢。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"하아… 그럼, 이렇게 하자, 리온.","JPN":"はあ……じゃあ、こうしよう。リオン。","ENG":"*Sigh...* Then let's do this, Liona.","TWN":"唉……那就這樣吧，萊恩。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"일단 우리가 머물고 있는 세이프 하우스에서 한동안 같이 지내는 거야.","JPN":"とりあえず、しばらくは私たちが泊まってるセーフハウスで過ごそう。","ENG":"For now, you can stay with us at the safe house.","TWN":"先到我們現在的安全據點一起住一陣子。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"초대장을 보냈다는 프리드웬이라는 곳은 우리가 같이 찾아 줄게.","JPN":"招待状を送った、そのプリドウェンってところは私たちも一緒に探す。","ENG":"We'll help you look into this Prydwen place together.","TWN":"我們陪你一起找那個寄出邀請函的普利多溫。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"여차하면 리코리스한테 부탁하면 되니까, 그 편이 지금보다 훨씬 나을 거야, 어때?","JPN":"いざとなったらリコリスに頼めばいいし。その方が今よりはマシなはず。どう？","ENG":"If things get complicated, we can ask Lycoris for help. That would be much better than now. What do you think?","TWN":"真有狀況的話拜託莉克麗絲就好，一定會比現在好。怎麼樣？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나, 나야 좋지만…….","JPN":"そ、そうしてくれると助かるけど……","ENG":"I mean, I would like that, but...","TWN":"我、我是沒問題啦……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"그, 그래도 괜찮을까? 내가 갑자기 너무 민폐 끼치는 거 아니야?","JPN":"いいの？　急に迷惑かけすぎじゃない？","ENG":"A-are you sure that's okay? Wouldn't I be imposing too much?","TWN":"可是真的可以嗎？我會不會突然太給你們添麻煩？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"민폐라니…….","JPN":"迷惑なわけないだろ。","ENG":"Imposing...?","TWN":"什麼添麻煩……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"친구잖아? 이 정도는 당연하지","JPN":"友達でしょ？　これぐらい当然だよ。","ENG":"We're friends! Of course it is fine.","TWN":"我們是朋友吧？這點事很正常啊"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"응……!","JPN":"うん……！","ENG":"Okay...!","TWN":"嗯……！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"고마워, 도로───────","JPN":"ありがとう、ドロ───────","ENG":"Thank you, Doro——","TWN":"謝謝你，桃樂──────"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"케흑!?","JPN":"ゴホッ！？","ENG":"Kuh?!","TWN":"咳！？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"어라…? 이상하다……?","JPN":"あれ……？　おかしいな……","ENG":"Huh...? That's strange...","TWN":"咦……？奇怪……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWORD_OZ_NULL_NULL","text":{"KOREA":"나, 하나도 안 아픈데… 왜 갑자기 피가 나지……?","JPN":"私、全然痛くないのに……どうして血が……？","ENG":"I don't feel any pain at all... Then why am I suddenly bleeding...?","TWN":"我一點都不痛……為什麼會突然流血……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_QM","text":{"KOREA":"왜냐하면 네 신경을 마비시켜두었기 때문이다. 신의 그릇이여.","JPN":"貴様の神経を麻痺させておいたからだ。神の器よ。","ENG":"Because I have paralyzed your nerves. God's vessel.","TWN":"因為我已經麻痺你的神經了，神之器皿。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_QM","text":{"KOREA":"원래 등 뒤에서 급소를 기습당하면 아무 말도 못할 정도로 고통을 느끼기 미련이거든.","JPN":"人間は背後から急所を突かれると、言葉も発せないほどの苦痛を感じるものだ。","ENG":"When one is struck in a vital spot from behind, the pain is often too great to even scream.","TWN":"若從背後刺中要害，原本會痛到連話都說不出口。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_QM","text":{"KOREA":"아무리 희생양이라고 할지라도, 나 또한 어린양에게 고통을 주고 싶지 않으니까.","JPN":"いくら生贄とはいえ、私とて哀れな子羊に余計な苦しみを与えたくはない。","ENG":"Even if you are a sacrifice, I have no desire to inflict suffering upon a lamb.","TWN":"就算是祭品，我也不想讓羔羊承受痛苦。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWORD_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"리, 리온!!","JPN":"リ、リオン！！","ENG":"L-Liona!!","TWN":"萊、萊恩！！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"등 뒤의 칼날이… 복부까지……!?","JPN":"後ろから剣が……腹部を貫通して……！？","ENG":"The blade from behind... it went all the way to the abdomen...?!","TWN":"背後的刀刃……貫穿到腹部了……！？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시, 출혈량이 심각해! 장기를 다쳤을 거야! 빨리 조치해야 해!","JPN":"ドロシー、ひどい出血だよ！　臓器をやられてる！　早く手当しないと！","ENG":"Dorothy, the blood loss is severe. Her organs must be damaged. We need to act now.","TWN":"桃樂絲，出血量太大了！內臟受損！得立刻處理！"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"안심해라, 어리석은 자들이여.","JPN":"安心しろ、愚か者ども。","ENG":"Do not worry, foolish ones.","TWN":"放心吧，愚蠢的眾人。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L26_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"파편을 품고 있는, 신의 그릇이 고작 이 정도로 절명할 리 없으니까.","JPN":"破片が宿っている神の器が、これしきのことで絶命したりはしない。","ENG":"A vessel that carries the Fragment would not perish from something like this.","TWN":"懷抱碎片的神之器皿，不可能因為這點程度的傷就死去。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"파편이라고……?","JPN":"破片……？","ENG":"Fragment...?","TWN":"碎片……？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"허나, 절망해라.","JPN":"だが、絶望するが良い。","ENG":"But despair.","TWN":"但是，絕望吧。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_SWORD_MOVEMENT"},{"id":"L32_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"벗조차 지킬 수 없는 가혹한 현실에 말이지.","JPN":"友すら守れない過酷な現実に。","ENG":"Despair at the cruel reality where you cannot even protect your friend.","TWN":"面對無法守護同伴的殘酷現實。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};